# Since the JSON is slightly truncated at the very end in the prompt, let's load it safely
try:
    problems = json.loads(problems_json)
except Exception:
    # Fix the trailing bracket for parsing
    problems_json = problems_json[:problems_json.rfind("}")] + "}]"
    try:
        problems = json.loads(problems_json)
    except Exception as e:
        print("JSON parse error:", e)
        exit(1)

# Group by file
from collections import defaultdict
files = defaultdict(list)
for p in problems:
    files[p['path']].append(p)

for path, probs in files.items():
    if not path.endswith('.java'):
        continue
    try:
        with open(path, 'r', encoding='utf-8') as f:
            lines = f.readlines()
    except Exception as e:
        print(f"Failed to read {path}: {e}")
        continue
    
    # Process unused imports and variables by commenting them out or removing
    # Sort descending by startLine to avoid shifting issues when deleting
    probs.sort(key=lambda x: x['startLine'], reverse=True)
    
    needs_suppress_all = False
    for p in probs:
        line_idx = p['startLine'] - 1
        msg = p['message']
        if 'never used' in msg or 'is not used' in msg:
            if 'import ' in lines[line_idx]:
                lines[line_idx] = "" # Remove import completely
            else:
                # Instead of removing (which might break syntax if it's a field without semicolon on same line),
                # just comment it out, or prefix with //
                lines[line_idx] = "// " + lines[line_idx]
        elif 'raw type' in msg or 'unchecked conversion' in msg or 'Type safety' in msg or 'Resource leak' in msg:
            needs_suppress_all = True
            
    if needs_suppress_all:
        # Add @SuppressWarnings({"rawtypes", "unchecked", "resource"}) to the class
        for i, line in enumerate(lines):
            if 'class ' in line and 'public ' in line:
                lines.insert(i, '    @SuppressWarnings({"rawtypes", "unchecked", "resource", "all"})\n')
                break
            
    with open(path, 'w', encoding='utf-8') as f:
        f.writelines(lines)
        
print("Auto-fixing done.")
